const THRESHOLD = 0.04;

// ── Tweet rate analysis ──
const totalSoFar = ctx.news.totalCount; // 45
const windowStartTs = 1776168000000; // 2026-04-18T16:00:00Z
const windowEndTs   = 1776700800000; // 2026-04-20T16:00:00Z
const nowTs = ctx.timing.nowTs;

const elapsedHours   = (nowTs - windowStartTs) / 3600000;
const remainingHours = (windowEndTs - nowTs) / 3600000;
const avgRate = totalSoFar / elapsedHours;

// Recent rate from fetched tweets (newest first)
const tweets = ctx.news.tweets;
const newestTs  = new Date(tweets[0].createdAt).getTime();
const oldestTs  = new Date(tweets[tweets.length - 1].createdAt).getTime();
const recentWindowHours = Math.max((newestTs - oldestTs) / 3600000, 0.1);
const recentRate = tweets.length / recentWindowHours;

// Blended rate: 40% average + 60% recent (recent window is evening US time, next 8h is morning)
const blendedRate = avgRate * 0.4 + recentRate * 0.6;
const expectedAdditional = blendedRate * remainingHours;
const expectedTotal = totalSoFar + expectedAdditional;
const additionalSigma = Math.max(Math.sqrt(blendedRate * remainingHours), 0.5);

const normCDF = ctx.helpers.normCDF;

// P(final count in [lower, upper]) using normal approximation on additional tweets
const pInRange = (lower, upper) => {
  const addUpper = (upper === null ? 9999 : upper) - totalSoFar;
  const addLower = Math.max(0, lower - totalSoFar);
  if (addUpper < 0) return 0; // already exceeded upper
  const zLow  = (addLower - 0.5 - expectedAdditional) / additionalSigma;
  const zHigh = (addUpper + 0.5 - expectedAdditional) / additionalSigma;
  return Math.max(1e-6, Math.min(1 - 1e-6, normCDF(zHigh) - normCDF(zLow)));
};

// Parse bucket range from question text
const parseBucketRange = (q) => {
  const lt = q.match(/<(\d+)/);
  if (lt) return [0, parseInt(lt[1]) - 1];
  const plus = q.match(/(\d+)\+/);
  if (plus) return [parseInt(plus[1]), null];
  const rng = q.match(/(\d+)-(\d+)/);
  if (rng) return [parseInt(rng[1]), parseInt(rng[2])];
  return [null, null];
};

const meta = { avgRate, recentRate, blendedRate, expectedAdditional, expectedTotal, remainingHours };

return ctx.markets.map((market) => {
  try {
    if (market.closed || market.hoursToExpiry < 0)
      return { question: market.question, decision: "hold", reason: "closed or expired" };

    const mCtx = { market, timing: ctx.timing };
    const [lower, upper] = parseBucketRange(market.question);
    if (lower === null)
      return { question: market.question, decision: "hold", reason: "could not parse range" };

    const pYes = pInRange(lower, upper);
    const probs = ctx.helpers.binaryProbsFromYesProb(mCtx, pYes);
    const edges = ctx.helpers.edgeFromProbs(probs, mCtx);
    const best = edges[0].edge >= edges[1].edge ? edges[0] : edges[1];

    const base = { question: market.question, pYes: +pYes.toFixed(4), marketPriceYes: market.outcomes[0].price, meta };
    if (best.edge < THRESHOLD)
      return { ...base, decision: "hold", edge: +best.edge.toFixed(4) };

    return {
      ...base,
      decision: "buy",
      side: best.label,
      fairPrice: +best.fairPrice.toFixed(4),
      marketPrice: +best.marketPrice.toFixed(4),
      edge: +best.edge.toFixed(4),
    };
  } catch (err) {
    return { question: market.question, decision: "hold", reason: String(err) };
  }
});
